import React from "react"; // ✅ Only necessary import

const About = () => {
  return (
    <div
      id="about-section" // Used for scrolling
      style={{
        padding: "50px 20px",
        backgroundColor: "#f5f5f5",
        textAlign: "center",
      }}
    >
      <h2>About Us</h2>
      <p>
        Welcome to our website! Here is some information about us. You can
        describe your services, mission, or anything else here.
      </p>
    </div>
  );
};

export default About;
